288	  void try_accept_socket()
289	  {
290	    if (this->socket) {
291	      spdlog::warn(
292	        "jtag_dtm: calling try_accept_socket() when a socket is already connected");
293	      return;
294	    }
295	
296	    auto socket = tcp::socket{asio::system_executor{}};
297	    auto ec = boost::system::error_code{};
298	    this->acceptor.accept(socket, ec);
299	    if (ec == asio::error::try_again)
300	      return;
301	
302	    if (ec)
303	      throw std::system_error{ec, "accept"};
304	
305	    socket.non_blocking(true);
306	    spdlog::info("jtag_dtm: accepted connection from {}:{}",
307	                 socket.remote_endpoint().address().to_string(),
308	                 socket.remote_endpoint().port());
309	    this->socket = std::move(socket);
310	  }
